            view: WebView,
            request: WebResourceRequest
        ): WebResourceResponse? {
            val url = request.url
            val urlString = url.toString()

            if (request.method == "GET") {
                // First try the asset loader
                loader!!.shouldInterceptRequest(url)?.let { return it }

                // Handle file:// URLs from media directory to enable JavaScript access (same-origin policy)
                //
                // Background: When SVG files are loaded with file:// scheme and the HTML is loaded via http://,
                // JavaScript cannot access the SVG's contentDocument due to CORS (same-origin policy).
                // This causes: "Uncaught TypeError: Cannot read properties of null (reading 'querySelectorAll')"
                //
                // Solution: Intercept file:// requests and serve them through the WebView itself, making them
                // appear to come from the same origin. This allows JavaScript to access SVG contentDocument.
                if (urlString.startsWith("file://")) {
                    url.path?.let { path ->
                        val file = File(path)
                        // Check if the file exists and is in the media directory (for security)
                        val mediaDir = CollectionHelper.getMediaDirectory(this@AbstractFlashcardViewer)
                        if (file.exists() && file.absolutePath.startsWith(mediaDir.absolutePath)) {
                            migrationService?.migrateFileImmediately(file)
                            try {
                                val inputStream = FileInputStream(file)
                                val mimeType = guessMimeType(file.name)
                                Timber.d("Intercepting file:// request: %s (MIME type: %s)", file.name, mimeType)
                                // Serve with proper MIME type to enable JavaScript access
                                return WebResourceResponse(mimeType, "UTF-8", inputStream)
                            } catch (e: Exception) {
                                Timber.w(e, "Failed to serve file: %s", file.name)
                            }
                        }
                    }
                }
            }
            return null
        }"}

